diff --git a/source/pdf/pdf-font.c b/source/pdf/pdf-font.c
index e071e8bd4..6e23a798d 100644
--- a/source/pdf/pdf-font.c
+++ b/source/pdf/pdf-font.c
@@ -565,8 +565,7 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 				fz_buffer *cff = pdf_extract_cff_subtable(ctx, data, size);
 				if (cff)
 				{
-					fz_drop_buffer(ctx, buf);
-					buf = cff;
+					buf = cff; // Transfer ownership, cff becomes buf
 				}
 			}
 		}
@@ -578,7 +577,11 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 	fz_catch(ctx)
 		fz_rethrow(ctx);

-	fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
+	// Only update size if font creation succeeded
+	if (fontdesc->font)
+		// Only add buffer size if font was successfully created
+	if (fontdesc->font)
+		fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
 	fontdesc->is_embedded = 1;
 }

